SELECT description
FROM test_suites
WHERE tsid = '1';

SELECT expected_result
FROM test_steps
WHERE step_id = 1;

SELECT created_by, COUNT(step_id) AS total_steps_created
     FROM test_steps
     GROUP BY created_by;

SELECT e.execution_time
FROM test_executions e
WHERE e.result = 'fail';

SELECT DISTINCT username
FROM users
WHERE user_id IN (
  SELECT user_id
  FROM test_executions
);

SELECT framework, COUNT(DISTINCT tsid) AS unique_test_suites
FROM test_suites
GROUP BY framework;
